ON CONFLICT (slug) DO UPDATE SET
    corpus_version     = EXCLUDED.corpus_version,
    option_patterns    = EXCLUDED.option_patterns,
    transient_patterns = EXCLUDED.transient_patterns,
    table_patterns     = EXCLUDED.table_patterns,
    cron_hook_patterns = EXCLUDED.cron_hook_patterns,
    updated_at         = now();

-- Write guard (DEFERRED from m40 so the seed INSERTs above run while wpmgr_app
-- still holds the m1 ALTER DEFAULT PRIVILEGES INSERT grant). After the corpus
-- is seeded, revoke all DML from the application role: the corpus is writable
-- only via the owner/superuser DSN at migration time. End state: wpmgr_app has
-- SELECT only (RLS SELECT policy + this REVOKE), under either DSN model.
REVOKE INSERT, UPDATE, DELETE ON plugin_signatures FROM wpmgr_app;
